var e=JSON.parse(`[{"id":"L1_1","type":"subtitle","speaker":null,"text":{"KOREA":"02:17 AM <color=#ffd34c>샤레이드</color>, 혁신기업지구\\n<color=#ffd34c>임시 지휘소</color> 섬멸작전 브리핑 중","JPN":"02:17 AM <color=#ffd34c>シャレード</color>, 革新企業地区\\n<color=#ffd34c>臨時指揮所</color>殲滅作戦ブリーフィング中","ENG":"02:17 AM <color=#ffd34c>Charade</color>, Innovative Business Sector\\n<color=#ffd34c>Temporary Command Center</color> Elimination Operation Briefing","TWN":"02:17 AM <color=#ffd34c>查雷德</color>, 創新企業區\\n<color=#ffd34c>臨時指揮中心</color> 殲滅戰簡報中"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"RIFLE_FOX_NULL_NULL","text":{"KOREA":"좋아, 친구들. 현 시간부로 관리국으로부터 섬멸작전 지시가 떨어졌다.","JPN":"よし、みんな。現時刻を持って管理局から殲滅作戦指示が下った。","ENG":"Hello friends, the Administration just green-lighted the elimination operation.","TWN":"好的，朋友們。收到來自管理局的指令。"},"stage":{"bg":"WAREHOUSE_03","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIFLE_FOX_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_PHONE"},{"id":"L4_1","type":"dialog","speaker":"RIFLE_FOX_NULL_NULL","text":{"KOREA":"도시관리국의 의향에 따라 이번 건은 우리 페넥 폭스가 주관하기로 했어.","JPN":"都市管理局の希望によって、この件は我々フェネックフォックスが担当することになったぞ。","ENG":"As per City Managements’ instructions, we, Fennec Fox will be in charge this time.","TWN":"照城市管理局的意思，此次行動由我們沙狐主導。"},"stage":{"bg":"WAREHOUSE_03","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIFLE_FOX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"RIFLE_FOX_NULL_NULL","text":{"KOREA":"불만 있는 사람?","JPN":"不満ある人？","ENG":"Any objections?","TWN":"有人有意見嗎？"},"stage":{"bg":"WAREHOUSE_03","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIFLE_FOX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"DRACO_NPC_SUMMER_NULL","text":{"KOREA":"네, 여기 한 명.","JPN":"はーい、あたし。","ENG":"I object.","TWN":"有，我有意見。"},"stage":{"bg":"WAREHOUSE_03","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"DRACO_NPC_SUMMER_NULL","text":{"KOREA":"왜 먼지 풀풀 날리는 구닥다리 아재가 대장 행세야? 나 이거 업계 부조리로 신고해도 돼?","JPN":"なんでこの古臭いおっさんが隊長なの？　パワハラで訴えてもいいよね？","ENG":"Why are you the boss? You’re just an old man who knows nothing. I’m going to file a complaint for this.","TWN":"為什麼是全身都灰塵的大叔當隊長？我可以跟勞工局申訴嗎？"},"stage":{"bg":"WAREHOUSE_03","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"RIFLE_FOX_NULL_NULL","text":{"KOREA":"설마. 관리국에서 실력 좋은 뉴페이스들이 편하게 활약하라고 정한 인선이지.","JPN":"まさか。実力のある新人たちが気楽に活躍できるように管理局から決めた人選、ってわけだ。","ENG":"Hey, they chose me so that you, amazing newcomers can go wild without worries.","TWN":"別這樣，管理局的美意是要讓有能力的新面孔可以輕鬆展現實力吧。"},"stage":{"bg":"WAREHOUSE_03","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIFLE_FOX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"RIFLE_FOX_NULL_NULL","text":{"KOREA":"자질구레한 일들은 우리가 처리해 줄게. 마음껏 날뛰어 보라고.","JPN":"細かい仕事は私たちに任せて、思いっきり暴れてきな！","ENG":"I’ll take care of the miscellaneous tasks. You go ahead and have fun in the field.","TWN":"像這種雞毛蒜皮的小事我們來處理就好！你就盡情玩樂吧！"},"stage":{"bg":"WAREHOUSE_03","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIFLE_FOX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"DRACO_NPC_SUMMER_NULL","text":{"KOREA":"어쩐다. 허접들이 응원해 줘 봤자 의욕은 하나도 안 나는데.","JPN":"どうかなー。雑魚たちから応援されてもぜーんぜんやる気出ないんだよなー。","ENG":"Oh well, such comment from a low critter like you don’t cheer me up at all.","TWN":"怎麼辦～面對這些傢伙一點都提不起勁～"},"stage":{"bg":"WAREHOUSE_03","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ZENA_CIVIL_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_LAUGH"}}}},{"id":"L13_1","type":"dialog","speaker":"ZENA_CIVIL_NULL_NULL","text":{"KOREA":"드라코 씨라고 하셨죠. 말씀 좀 가려 하세요.","JPN":"ドラコさんでしたよね。口調には気をつけてください。","ENG":"Dracasia, is it? Please watch your mouth.","TWN":"你叫德拉克對吧？說話請客氣一點。"},"stage":{"bg":"WAREHOUSE_03","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ZENA_CIVIL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_LAUGH"}}}},{"id":"L14_1","type":"dialog","speaker":"ZENA_CIVIL_NULL_NULL","text":{"KOREA":"페넥폭스 협동조합은 로터스 수복에 공헌했던 분들이라고요. 업계 선배님들께 최소한의 예의는 갖춰야죠.","JPN":"フェネックフォックスは、ロータスの修復に貢献した方々です。業界の先輩たちに最低限のマナーは守るべきでしょう。","ENG":"Fennec Fox Association contributed greatly to the Lotus recovery operation. Show some respect to the veterans.","TWN":"沙狐可是收復洛德斯的大功臣，對業界的前輩請保持禮貌。"},"stage":{"bg":"WAREHOUSE_03","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ZENA_CIVIL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_LAUGH"}}}},{"id":"L15_1","type":"dialog","speaker":"DRACO_NPC_SUMMER_NULL","text":{"KOREA":"와, 순무가 말도 할 줄 아네.","JPN":"へえー、カブが喋ってる。","ENG":"Why, a talking turnip.","TWN":"哇，蔥會說話欸！"},"stage":{"bg":"WAREHOUSE_03","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ZENA_CIVIL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"ZENA_CIVIL_NULL_NULL","text":{"KOREA":"누, 누가 순무라는 건데요!","JPN":"だ、誰がカブですか！","ENG":"I, I’m not a turnip!","TWN":"你…你說誰是蔥！"},"stage":{"bg":"WAREHOUSE_03","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ZENA_CIVIL_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"DRACO_NPC_SUMMER_NULL","text":{"KOREA":"몰랐어? 너 이미 SNS에 소문 쫙 퍼졌는데?","JPN":"知らないんだ。君、SNSで有名になってるよ？","ENG":"You didn’t know? It’s all over the social networks.","TWN":"你不知道喔？你現在在網路上超火欸！"},"stage":{"bg":"WAREHOUSE_03","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ZENA_CIVIL_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"DRACO_NPC_SUMMER_NULL","text":{"KOREA":"그런 꼴 당하고 잘도 얼굴을 들이미네. 관리국 직할이란 이름이 부끄럽지도 않아?","JPN":"そんな恥をかいてよくここまで来れたね。管理局の直轄ってタイトルが恥ずかしくないの？","ENG":"Shame on you. You’re supposed to be an Administration official Counter, yet here you are.","TWN":"被弄成倒栽蔥還有臉出來說話，你不覺得有愧於管理局直轄之名嗎？"},"stage":{"bg":"WAREHOUSE_03","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ZENA_CIVIL_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"ZENA_CIVIL_NULL_NULL","text":{"KOREA":"크읏……!","JPN":"くっ……！","ENG":"Hmph...!","TWN":"唔……！"},"stage":{"bg":"WAREHOUSE_03","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ZENA_CIVIL_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"RIFLE_FOX_NULL_NULL","text":{"KOREA":"하하, 싸울 것 없어. 로터스를 되찾은 건 우리보다 한참 윗 기수 분들이니까.","JPN":"まあまあ、喧嘩することないさ。ロータスを取り戻したのは私たちよりも遥かに上の先輩たちだからな。","ENG":"Haha, calm down, everyone. Lotus was recovered by our seniors, not us. So it’s okay.","TWN":"哈哈～沒什麼好吵的。收復洛德斯的是比我們更厲害的人。"},"stage":{"bg":"WAREHOUSE_03","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIFLE_FOX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"RIFLE_FOX_NULL_NULL","text":{"KOREA":"그래도 우리처럼 변변찮은 사람들이 있어야 너희들 실력도 더 빛나지 않겠어?","JPN":"でも、私たちのような非能力者がいるからこそ、君たちの実力も目立つだろ？","ENG":"But you still need foot soldiers like us to outshine others. Don’t you agree?","TWN":"不過就是要有像我們這種綠葉，才更能襯托出你們的厲害不是嗎？"},"stage":{"bg":"WAREHOUSE_03","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIFLE_FOX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"ZENA_CIVIL_NULL_NULL","text":{"KOREA":"아, 아닙니다! 시끄럽게 해서 죄송해요!","JPN":"は、はい！　騒がしてすみません！","ENG":"That’s not true! I-I’m sorry for the commotion!","TWN":"抱…抱歉！打斷簡報！"},"stage":{"bg":"WAREHOUSE_03","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ZENA_CIVIL_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L26_1","type":"dialog","speaker":"ZENA_CIVIL_NULL_NULL","text":{"KOREA":"저게 바로 너그러운 리더의 태도구나……! 나도 언젠가는……!","JPN":"あれがリーダーが持つべき優しい態度なんだ……！　私もいつか……！","ENG":"Such a respectable leader with an open mind! I wish I could be like him someday...","TWN":"原來那就是身為領袖該有的風範……！總有一天我也……！"},"stage":{"bg":"WAREHOUSE_03","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ZENA_CIVIL_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L27_1","type":"dialog","speaker":"DRACO_NPC_SUMMER_NULL","text":{"KOREA":"뭐야, 반응까지 시시해. 갖고 노는 재미도 없게.","JPN":"なんだー、つまらない反応。からかい甲斐がないじゃん。","ENG":"This is boring. It’s no fun when you’re so calm like that.","TWN":"什麼嘛～反應也這麼無趣，想跟你鬥嘴都覺得沒勁。"},"stage":{"bg":"WAREHOUSE_03","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ZENA_CIVIL_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"LIV_ZODIAC_NULL_NULL","text":{"KOREA":"그래서 섬멸작전이 뭐야? 어떻게 하면 되는데?","JPN":"それで、殲滅作戦ってなに？　どうすればいいの？","ENG":"So what’s this operation about? What do we eliminate?","TWN":"所以殲滅戰到底是什麼？要怎麼做？"},"stage":{"bg":"WAREHOUSE_03","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"RIFLE_FOX_NULL_NULL","text":{"KOREA":"저 본사 건물 안에 득실거리는 녀석들을 실컷 해치우는 거지.","JPN":"あの本社建物の中にうようよしているやつらを倒せばいいのさ。","ENG":"Kill as many creatures as you can in that main building over there.","TWN":"簡單說就是將總公司內的傢伙趕盡殺絕的意思。"},"stage":{"bg":"WAREHOUSE_03","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIFLE_FOX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"RIFLE_FOX_NULL_NULL","text":{"KOREA":"선발대가 측정한 내부 CSE 레벨은 급격히 줄어들었다고는 하지만, 그림자 전당 현상도 목격되는 상태야.","JPN":"先発隊が測定した内部のCSEレベルは急激に下がっているものの、影の殿堂まで目撃されている状態だ。","ENG":"The advance team reported that the CSE Level within the building has greatly decreased, but we’re seeing some Shadow Palaces phenomenon as well.","TWN":"雖然先遣部隊說偵測到的內部CSE等級疾速下降中，但也有發現到暗影殿堂現象。"},"stage":{"bg":"WAREHOUSE_03","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIFLE_FOX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"RIFLE_FOX_NULL_NULL","text":{"KOREA":"조금만 방치했다간 침식체들이 뿜어내는 침식파 때문에 얼마 못 가 CSE 레벨이 다시 상승할 거다.","JPN":"このままだと、侵食体が出す侵食波のせいで近いうちにCSEレベルが再び上昇するだろう。","ENG":"If we don’t remove Corrupted Objects in the building quickly, the Corruption Ray they radiate will increase the CSE Level again.","TWN":"不趕快處理的話，不用多久，CSE等級就又會因為侵蝕體釋放出的侵蝕波而上升。"},"stage":{"bg":"WAREHOUSE_03","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIFLE_FOX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"MIYA_HB_NULL_NULL","text":{"KOREA":"저, 저기……. 루미야. 우린 역시 빠지는 게 좋지 않을까?","JPN":"あ、あの……ルミ。私たちはやっぱり行かない方がいいんじゃない？","ENG":"Um, Lumi. Maybe we should just leave.","TWN":"那個……魯米，我們是不是不要插手比較好？"},"stage":{"bg":"WAREHOUSE_03","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RUMI_HB_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"MIYA_HB_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L36_1","type":"dialog","speaker":"RUMI_HB_NULL_NULL","text":{"KOREA":"무슨 소리야. 내 뒤에만 찰싹 붙어 있으라구.","JPN":"なに言ってるの！　あたしの後ろにしっかりついていれば問題ないわよ！","ENG":"What are you talking about? Just stay with me, and you’ll be fine.","TWN":"說什麼傻話！你就在我後面躲好！"},"stage":{"bg":"WAREHOUSE_03","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RUMI_HB_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MIYA_HB_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L37_1","type":"dialog","speaker":"RUMI_HB_NULL_NULL","text":{"KOREA":"태스크포스들 사이에서 대활약! 이거라면 그 사채업자 잡는 만큼 스포트라이트도 쏟아질걸?","JPN":"タスクフォースカンパニーの間で大活躍！　これなら、あの闇金業者を捕まえなくてもスポットライトを浴びるに決まってるわ！","ENG":"Think about it; us running along with TASKFORCEs. It will put us back in the spotlight, just like the time when we caught the loan shark!","TWN":"只要抓到那個放高利貸，我們就會成為焦點新聞！新聞標題就是，全網震驚！在特遣勢力中大放異彩！"},"stage":{"bg":"WAREHOUSE_03","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RUMI_HB_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"MIYA_HB_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L39_1","type":"dialog","speaker":"RIFLE_FOX_NULL_NULL","text":{"KOREA":"스포트라이트가 쏟아질지는 모르겠지만, 관리국에서 보상은 제대로 챙겨 줄 거야.","JPN":"スポットライトを浴びられるかどうかは知らないが、管理局から報酬はちゃんと出るはずだ。","ENG":"I’m not sure about the spotlights, but the Administration will pay you nicely...","TWN":"會不會有記者報導我是不確定，但管理局大大有賞這是肯定的。"},"stage":{"bg":"WAREHOUSE_03","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIFLE_FOX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"RIFLE_FOX_NULL_NULL","text":{"KOREA":"어디까지나 자기들이 요구하는 실적을 증명했을 때의 이야기지만.","JPN":"あくまで管理局から要求されたノルマを達成した時の話だがな。","ENG":"Only if you meet the bar they set.","TWN":"當然前提是，你必須證明自己的能力。"},"stage":{"bg":"WAREHOUSE_03","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIFLE_FOX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"DRACO_NPC_SUMMER_NULL","text":{"KOREA":"설마 그것도 못할까 봐 걱정하는 쓰레기가 있으려나? 용병이면서 창피하게?","JPN":"まさか、ノルマも達成できないクズがいるとでも？　傭兵なのに恥ずかしいー。","ENG":"What kind of mercenary worries about meeting their pathetic bar?","TWN":"拜託～有擔心連那種小事都辦不到的垃圾嗎？這麼丟傭兵的臉？"},"stage":{"bg":"WAREHOUSE_03","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"DRACO_NPC_SUMMER_NULL","text":{"KOREA":"겁쟁이들은 찌그러져 있으라고 해. 보상은 내 차지니까.","JPN":"雑魚たちは適当に隠れてろよ。報酬はあたしのものだからな。","ENG":"To hell with incompetent cowards. The rewards are all mine.","TWN":"膽小鬼都給我走開！獎賞是我的！"},"stage":{"bg":"WAREHOUSE_03","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RIFLE_FOX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_PRIDE"}}}},{"id":"L45_1","type":"dialog","speaker":"RIFLE_FOX_NULL_NULL","text":{"KOREA":"하하, 믿음직스러운데.","JPN":"はは、頼もしいな。","ENG":"Haha, I look forward to it.","TWN":"呵呵，真是可靠呢。"},"stage":{"bg":"WAREHOUSE_03","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RIFLE_FOX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_PRIDE"}}}},{"id":"L46_1","type":"dialog","speaker":"RIFLE_FOX_NULL_NULL","text":{"KOREA":"그럼 다들 출발할 준비해. 선발대는 한창 휘젓고 다니는 중이야.","JPN":"それでは、みんな出発してくれ。先発隊はだいぶ前に出発したんだ。","ENG":"Everyone, get ready. The advance team is already in action.","TWN":"那麼大家準備出發吧！先遣部隊應該正在激戰中。"},"stage":{"bg":"WAREHOUSE_03","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RIFLE_FOX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_PRIDE"}}}},{"id":"L47_1","type":"dialog","speaker":"DRACO_NPC_SUMMER_NULL","text":{"KOREA":"벌써? 거긴 꽤 한가닥 하는 녀석이라도 있나 봐?","JPN":"もう？　先発隊にも結構腕のいいやつがいるんだな？","ENG":"Already? Who do they have on the team? Some strongman?","TWN":"他們已經開始打啦？看來那當中應該有狠角色喔？"},"stage":{"bg":"WAREHOUSE_03","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RIFLE_FOX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_LAUGH"}}}},{"id":"L48_1","type":"dialog","speaker":"RIFLE_FOX_NULL_NULL","text":{"KOREA":"우리야 모르지. 상황이 급하니까 그 체포됐다는 수배자라도 투입했을지도 모르고.","JPN":"まあ、私たちもそこまではわからないさ。状況が状況だからあの指名手配者を投入したかも知れないし。","ENG":"Who knows. They could have sent the wanted criminal they arrested, considering the graveness of the situation.","TWN":"這我們不清楚，因為情況緊急，或許那個被抓到的通緝犯也有投入作戰也說不定。"},"stage":{"bg":"WAREHOUSE_03","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RIFLE_FOX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_LAUGH"}}}},{"id":"L50_1","type":"dialog","speaker":"RIFLE_FOX_NULL_NULL","text":{"KOREA":"자. 그러니 지각해서 허탕 치지 않게 서둘러야겠지, 친구들?","JPN":"だから君たちも遅刻して手ぶらで帰らないように頑張ってくれよ！","ENG":"Now, hurry up before you miss all the fun, okay?","TWN":"不想因為遲到而白忙一場的話，就趕快出發吧，朋友們！"},"stage":{"bg":"WAREHOUSE_03","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIFLE_FOX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};